import{_ as a,c as e}from"./app.56afa649.js";const r={},t=e('<h1 id="tjana-pengar" tabindex="-1"><a class="header-anchor" href="#tjana-pengar" aria-hidden="true">#</a> Tj\xE4na pengar</h1><h2 id="var-version-foretag" tabindex="-1"><a class="header-anchor" href="#var-version-foretag" aria-hidden="true">#</a> V\xE5r version (f\xF6retag)</h2><p>Vi gillar att g\xF6ra saker annorlunda och d\xE4rf\xF6r har vi gjort s\xE5 att ist\xE4llet f\xF6r att du har ett jobb som tex &quot;miner&quot; s\xE5 jobbar du f\xF6r ett f\xF6retag. Om vi tar f\xF6retaget &quot;Bosses-Stenbrott&quot; s\xE5 \xE4r det i grund och botten jobbet som tidigare hette &quot;miner&quot;.</p><h2 id="loner" tabindex="-1"><a class="header-anchor" href="#loner" aria-hidden="true">#</a> L\xF6ner</h2><p>N\xE4r du har b\xF6rjat arbeta p\xE5 ett f\xF6retag s\xE5 kommer du f\xE5 l\xF6n d\xE4rifr\xE5n. Du har alltid en timl\xF6n dom \xE4r uppdelad p\xE5 fem utbetalningar i timmen (varje 12:e min.) F\xF6r att \xF6ka din timl\xF6n m\xE5ste du arbete med dom sysslorna som just det f\xF6retaget du jobbar f\xF6r sysslar med. Max niv\xE5n du kan n\xE5 \xE4r 200. H\xF6gst upp p\xE5 sk\xE4rmen f\xE5r du ett medelande varje g\xE5ng en l\xF6n betalas ut.</p><p>Om du inte arbetar f\xF6r n\xE5got f\xF6retag s\xE5 kommer du f\xE5 utbetalning fr\xE5n f\xF6rs\xE4kringskassan med en fast summa som aldrig kommer att \xF6ka.</p><h2 id="borja-arbeta" tabindex="-1"><a class="header-anchor" href="#borja-arbeta" aria-hidden="true">#</a> B\xF6rja arbeta</h2><p>F\xF6r att b\xF6rja arbeta ett f\xF6retag m\xE5ste du f\xF6rst prata med \xE4garen. I spawn hittar du en arbetsf\xF6rmedling d\xE4r Bosse, Wilma, Kent och Bullen h\xE5ller till. Dessa fyra \xE4r v\xE5ra arbetsgivare vi har p\xE5 servern. Prata med dom f\xF6r att l\xE4sa mer om just deras f\xF6retag och b\xF6rja arbeta.</p><h2 id="uppsagning-byta-foretag" tabindex="-1"><a class="header-anchor" href="#uppsagning-byta-foretag" aria-hidden="true">#</a> Upps\xE4gning/byta f\xF6retag</h2><p>Om du vill byta f\xF6retag och syssla med n\xE5got annat s\xE5 kan du prata med n\xE5gon av v\xE5ra arbetsgivare s\xE5 guidar dig dig till hur du s\xE4ger upp dig.</p><h2 id="vara-foretag" tabindex="-1"><a class="header-anchor" href="#vara-foretag" aria-hidden="true">#</a> V\xE5ra f\xF6retag</h2><h3 id="bosses-stenbrott" tabindex="-1"><a class="header-anchor" href="#bosses-stenbrott" aria-hidden="true">#</a> Bosses stenbrott</h3><p>Om det \xE4r mining du vill syssla med s\xE5 \xE4r Bosses stenbrott f\xF6retaget F\xF6r dig. Bosse betalar pengar till alla miners d\xE4r ute.</p><h3 id="wilmas-bonder" tabindex="-1"><a class="header-anchor" href="#wilmas-bonder" aria-hidden="true">#</a> Wilmas b\xF6nder</h3><p>Om det \xE4r plantera och sk\xF6rda gr\xF6nska, hugga ner tr\xE4d, ta hand om djur som du tycker \xE4r roligast s\xE5 \xE4r det Wilmas b\xF6nder du ska arbeta f\xF6r. Hon betalar n\xE4mligen ut pengar till alla b\xF6nder p\xE5 servern.</p><h3 id="bullens-bygg" tabindex="-1"><a class="header-anchor" href="#bullens-bygg" aria-hidden="true">#</a> Bullens bygg</h3><p>\xC4r bygga sin stora passion i minecraft? D\xE5 \xE4r det Bullens bygg du sak v\xE4nda dig till. Bullen betalar den som bygger.</p><h3 id="kents-jaktstuga" tabindex="-1"><a class="header-anchor" href="#kents-jaktstuga" aria-hidden="true">#</a> Kents jaktstuga</h3><p>\xC4r du som Kent och gillar att fiska, jaga, enchanta och brygga magiska drycker- D\xE5 \xE4r Kents jaktstuga det sj\xE4lvklara valet f\xF6r dig.</p><h2 id="snabb-guide-borja-arbeta" tabindex="-1"><a class="header-anchor" href="#snabb-guide-borja-arbeta" aria-hidden="true">#</a> Snabb guide &quot;B\xF6rja arbeta&quot;</h2><ol><li>G\xE5 till arbetsf\xF6rmedlingen</li><li>Prata med en NPC med det f\xF6retaget du vill jobba f\xF6r.</li><li>Klicka p\xE5 sida 2 och v\xE4lj &quot;b\xF6rja arbeta&quot;</li><li>Du har nu g\xE5tt med ett f\xF6retag</li><li>Skriv <code>/arbete</code> f\xF6r att se information om din plats i f\xF6retaget.</li></ol><h2 id="kommandon" tabindex="-1"><a class="header-anchor" href="#kommandon" aria-hidden="true">#</a> Kommandon</h2><p><em>Alla kommandon b\xF6rjar med /</em></p><ul><li><code>arbete</code> | Visar information om dig och hur du ligger till hos f\xF6retaget.</li><li><code>jobs browse</code> | \xD6ppna GUI med alla jobs d\xE4r du \xE4ven kan g\xE5 med/l\xE4mna jobb.</li><li><code>jobs leaveall</code> | L\xE4mnar ditt nuvarande arbete</li></ul>',24);function n(d,s){return t}var o=a(r,[["render",n],["__file","jobs.html.vue"]]);export{o as default};
